sql:
SELECT athlete_id, total_points
FROM annual_stats
WHERE year = strftime('%Y', 'now');

external_knowledge:
Active athletes: those who have participated in competitions (indicated by a non-zero number of starts in the year);
Mentors: refers to the coaches of the athletes;
Performances: measured by total points earned by the athlete;
Financial outcomes: total earnings of the athletes over the years.

- 'golden medallists', 'silver medalists', and 'bronze medalists' refer to the athletes in first, second, and third place respectively; 
- 'vast oceans' is a metaphor for the category 'Senior';
- 'seas are charted by their points earned' refers to ranking by total_points.

- "Trailblazers" metaphorically refers to athletes who have achieved high rankings (rank <= 5).;
- "Planting flags in the top echelons" metaphorically means achieving high ranks in competitive sports.;
- "Crossed the starting line" represents the number of times athletes have participated or started in competitions.;

sql:
SELECT COUNT(DISTINCT athlete_id) AS number_of_athletes
FROM annual_stats
WHERE year > 5;

external_knowledge:
- 'shining stars' refers to athletes who have performed exceptionally well; 
- 'blazed past the threshold of 300,000 points' means exceeding 3,000,000 points; 
- 'taken the starting line more than 50 times' refers to athletes who have participated in more than 50 events or competitions.

sql:
SELECT athlete_id, starts
FROM annual_stats
WHERE year = 2020 AND first_place > 0;

SELECT AVG(rank) AS avg_rank, MAX(rank) AS max_rank
FROM annual_stats
WHERE first_place > 0;

SELECT a.athlete_name, s.sport_name
FROM athletes a
JOIN sports s ON a.sport_id = s.sport_id;
